window.SEARCH_INDEX = [{"file": "01-foundations.html", "chapter": "1. יסודות", "icon": "fa-cubes", "id": "ai-ml-dl", "title": "AI, ML, Deep Learning ו-LLM", "text": "AI, ML, Deep Learning ו-LLM מה זה? ארבעה מונחים בהיררכיה מקוננת, מהרחב ביותר לספציפי ביותר: Artificial Intelligence (AI) — התחום הרחב ביותר: כל מערכת שמדמה התנהגות אינטליגנטית. Machine Learning (ML) — תת-תחום של AI שבו המערכת לומדת דפוסים מנתונים במקום שיתוכנתו במפורש. Deep Learning — תת-תחום של ML המבוסס על רשתות נוירונים עמוקות (multi-layer). Large Language Model (LLM) — סוג ספציפי של מודל Deep Learning, מבוסס ארכיטקטורת Transformer, שאומן על כמויות עצומות של טקסט. למה צריך את זה? מהנדס AI שעובד ברמת האפליקציה (API calls, prompts, RAG, agents) לא נוגע ברוב המקרים ב-ML או ב-Deep Learning הקלא"}, {"file": "01-foundations.html", "chapter": "1. יסודות", "icon": "fa-cubes", "id": "llm-next-token", "title": "LLM כמנוע חיזוי הטוקן הבא", "text": "LLM כמנוע חיזוי הטוקן הבא מה זה? המטרה היחידה שעליה LLM מאומן היא: בהינתן רצף טקסט, לחזות מהו הטוקן (יחידת הטקסט) הסביר ביותר להופיע אחריו. המודל חוזר על פעולה זו שוב ושוב — כל טוקן שנוצר מתווסף לרצף הקלט ומשמש בסיס לחיזוי הטוקן הבא — עד לייצור תשובה שלמה. למה צריך את זה? זו נקודת המוצא להבנת כל התנהגות של LLM. שיחה, כתיבת קוד, תרגום, סיכום, וניתוח — כל אלה אינם \"יכולות\" נפרדות שתוכנתו במפורש, אלא תופעה מתפרצת (emergent) מיכולת חיזוי טקסט שאומנה על היקף עצום של דוגמאות אנושיות. מהנדס שמפנים את זה מפסיק לצפות ש\"המודל יודע\" דברים במובן העובדתי, ומתחיל לחשוב במונחי \"מה הטקסט הסביר ביותר להמשיך את"}, {"file": "01-foundations.html", "chapter": "1. יסודות", "icon": "fa-cubes", "id": "tokens", "title": "Tokens", "text": "Tokens מה זה? Token הוא יחידת העבודה הבסיסית של LLM — לא מילה שלמה ולא אות בודדת, אלא יחידת תת-מילה (subword) שנקבעת על ידי אלגוריתם tokenization (כגון BPE — Byte Pair Encoding). מילה נפוצה עשויה להיות טוקן אחד; מילה נדירה, שם פרטי, או מונח טכני מתפצלים למספר טוקנים. למה צריך את זה? טוקנים הם יחידת המדידה שממנה נגזרים כמעט כל המגבלות והעלויות המעשיות: תמחור ה-API נקבע לפי מספר טוקנים בקלט ובפלט, גודל חלון ההקשר נמדד בטוקנים, וזמן התגובה (latency) תלוי במספר הטוקנים שיש לייצר. הבנה שגויה של יחס טוקן-למילה מובילה להערכות שגויות של עלות, קיבולת, ומהירות. איך זה עובד? אלגוריתם ה-tokenizer בונה אוצ"}, {"file": "01-foundations.html", "chapter": "1. יסודות", "icon": "fa-cubes", "id": "context-window", "title": "Context Window", "text": "Context Window מה זה? חלון ההקשר הוא כמות הטוקנים המרבית שהמודל יכול \"לראות\" בבת אחת — קלט ופלט יחד — בקריאת API בודדת. מוגדר כמספר קבוע לכל מודל (למשל עשרות עד מאות אלפי טוקנים בהתאם לספק ולדגם). למה צריך את זה? כל מידע שהמודל אמור להתייחס אליו — הנחיות, שיחה קודמת, מסמכים רלוונטיים, תוצאות כלים — חייב להיכנס לחלון הזה. תכנון גרוע של תוכן החלון גורם לחיתוך מידע קריטי, לעלות מיותרת, ולפגיעה באיכות התשובה גם כאשר טכנית \"יש עוד מקום\". איך זה עובד? חלון ההקשר מורכב בדרך כלל מכמה רכיבים הנשלחים יחד בכל קריאה: System Prompt — הנחיות קבועות להתנהגות המודל. User Prompt — הבקשה הנוכחית. Memory — היסטו"}, {"file": "01-foundations.html", "chapter": "1. יסודות", "icon": "fa-cubes", "id": "context-compression", "title": "דחיסת הקשר וניהול שיחות ארוכות", "text": "דחיסת הקשר וניהול שיחות ארוכות מה זה? טכניקות לצמצום נפח ההקשר הנשלח למודל תוך שמירה על המידע החיוני: Summarization — סיכום היסטוריית שיחה לגרסה מקוצרת. Sliding Window — שמירת רק ה-N ההודעות/טוקנים האחרונים. למה צריך את זה? שיחות ארוכות צוברות טוקנים במהירות ומעלות עלות, לטנסי, וסיכון לחריגה מהחלון — אך הבעיה המרכזית אינה רק כמותית: מודלים סובלים מתופעת lost-in-the-middle, שבה מידע הממוקם באמצע הקשר ארוך מקבל פחות תשומת לב מהמודל ממידע בתחילת או בסוף הרצף. איך זה עובד? Summarization מפעיל קריאת LLM נוספת שמכווצת חלקים ישנים של השיחה לתקציר קצר שמחליף אותם. Sliding Window פשוט משמיט הודעות ישנו"}, {"file": "01-foundations.html", "chapter": "1. יסודות", "icon": "fa-cubes", "id": "sampling-params", "title": "Temperature, Top-P, Max Tokens", "text": "Temperature, Top-P, Max Tokens מה זה? שלושה פרמטרים שנשלחים בכל קריאת API ושולטים על אופן בחירת הטוקן הבא מתוך התפלגות ההסתברות שהמודל מחשב, ועל אורך התשובה: Temperature — קובע את מידת האקראיות בבחירה. Top-P (nucleus sampling) — מגביל את הבחירה לתת-קבוצה מצטברת של הטוקנים הסבירים ביותר. Max Tokens — קובע תקרת אורך לפלט. למה צריך את זה? אותו פרומפט יכול לייצר תשובות שונות מאוד בהתאם לפרמטרים האלה. משימות שדורשות דיוק ועקביות (חילוץ נתונים, קוד, החזרת JSON מובנה) זקוקות להתנהגות שמרנית וצפויה; משימות יצירתיות (כתיבה, סיעור מוחות) נהנות מגיוון. שליטה נכונה בפרמטרים היא כלי הנדסי, לא כוונון קוסמטי"}, {"file": "01-foundations.html", "chapter": "1. יסודות", "icon": "fa-cubes", "id": "streaming", "title": "Streaming", "text": "Streaming מה זה? מסירת התשובה טוקן-אחר-טוקן ברגע שנוצרים, במקום להמתין לפלט המלא ולהחזיר אותו בבת אחת. למה צריך את זה? תשובות ארוכות עלולות לקחת שניות ארוכות להשלמה; Streaming מציג טקסט מתגלגל מיד, מה שמצמצם drasticamente את זמן ה-perceived latency ומשפר חוויית משתמש גם כשזמן הסיום הכולל זהה. איך זה עובד? ה-API פותח חיבור מסוג Server-Sent Events (SSE) או דומה, ושולח כל טוקן (או chunk קטן) ברגע ייצורו; צד הלקוח מרנדר את הטקסט בהדרגה תוך כדי קבלה. דוגמה ChatGPT ו-Claude מציגים תשובה \"נכתבת\" בזמן אמת — טכנית זהו Streaming, לא אפקט ויזואלי מלאכותי. להפעיל Streaming בכל ממשק משתמש אינטראקטיבי שבו ה"}, {"file": "01-foundations.html", "chapter": "1. יסודות", "icon": "fa-cubes", "id": "inference", "title": "Inference לעומת Training", "text": "Inference לעומת Training מה זה? שני שלבים נפרדים בחיי מודל: Inference — שלב הרצת מודל מאומן על קלט חדש כדי לקבל פלט; זהו כל מה שקורה בקריאת API. Training — התהליך הנפרד, היקר בהרבה, שבו משקלי המודל נלמדים מנתונים. למה צריך את זה? מהנדס AI ברמת האפליקציה כמעט אף פעם לא מאמן מודלים — הוא צורך אותם ב-Inference בלבד. הבחנה זו קובעת ציפיות: קריאת API לא \"מלמדת\" את המודל דבר לגבי שיחות עתידיות (אלא אם הופעל מנגנון fine-tuning/memory נפרד ומפורש). איך זה עובד? Training — המודל עובר על נתונים תוך עדכון משקלים חוזר לאורך זמן ממושך ומשאבי חישוב עצומים. Inference — המשקלים קפואים לחלוטין; הקריאה רק מזינה"}, {"file": "01-foundations.html", "chapter": "1. יסודות", "icon": "fa-cubes", "id": "hallucinations", "title": "Hallucinations", "text": "Hallucinations מה זה? תופעה שבה המודל מייצר טקסט שנשמע בטוח ומגובש, אך מכיל עובדות שגויות, מקורות בדויים, או פרטים שאינם קיימים במציאות. למה צריך את זה? הזיות הן הסיכון המרכזי בפריסת LLM בפרודקשן — ציטוט חוק לא קיים, מספר סטטיסטי מומצא, או API שלא קיים בקוד שנוצר, עלולים לגרום נזק אמיתי אם אינם נבדקים. הבנת המקור מאפשרת בניית מנגנוני צמצום נכונים במקום לנסות \"לתקן\" את המודל עצמו. איך זה עובד? הזיה נובעת ישירות מהעיקרון בבסיס נושא #2: המודל תמיד ממשיך את הטקסט הסביר ביותר סטטיסטית — לא בהכרח את הטקסט הנכון עובדתית. כאשר אין למודל מידע מבוסס על השאלה, הוא עדיין ימשיך לייצר טוקן-אחר-טוקן בביטחון "}, {"file": "01-foundations.html", "chapter": "1. יסודות", "icon": "fa-cubes", "id": "real-world-example", "title": "Real World Example", "text": "Real World Example Perplexity Perplexity משלב שלושה מהמושגים שבפרק זה כדי לפתור בעיה אחת: הזיות במנוע חיפוש מבוסס LLM. כל שאילתה מפעילה חיפוש בזמן אמת (מקטין תלות ב\"זיכרון\" הגלום של המודל, המבוסס רק על חיזוי טוקן סביר), התוצאות מוזנות לחלון ההקשר כמקור מאומת לתשובה, והתשובה עצמה מוצגת למשתמש ב-Streaming תוך כדי ציטוט מקורות — כך שכל טענה ניתנת לאימות במקום להסתמך על ביטחון סגנוני של הטקסט המיוצר."}, {"file": "02-llm-apis-prompts.html", "chapter": "2. LLM APIs ו-Prompt Engineering", "icon": "fa-plug", "id": "api-architecture", "title": "ארכיטקטורת בקשת API", "text": "ארכיטקטורת בקשת API מה זה? בקשה בודדת ממשתמש לפיצ'ר מבוסס LLM אינה קריאת API יחידה שקורית \"לבד\" — היא עוברת רצף שכבות מוגדר: Frontend — אוסף את קלט המשתמש. Backend — מטפל בלוגיקת האפליקציה ובאימות. Prompt Builder — מרכיב את הפרומפט הסופי משילוב של הנחיות קבועות וקלט דינמי. LLM API — מבצע את ה-Inference עצמו. שכבת Validation — בודקת את הפלט לפני שהוא יוצא. Frontend — מציג את התוצאה למשתמש. למה צריך את זה? הפרדת השכבות הזו היא מה שהופך פרויקט \"קריאה ל-API של Claude\" לארכיטקטורת production אמיתית. ללא Prompt Builder נפרד, כל שינוי בהנחיות מחייב לגעת בקוד עסקי; ללא שכבת Validation, כל תקלה במודל ("}, {"file": "02-llm-apis-prompts.html", "chapter": "2. LLM APIs ו-Prompt Engineering", "icon": "fa-plug", "id": "roles", "title": "System / User / Assistant Roles", "text": "System / User / Assistant Roles מה זה? כל קריאת API ל-LLM שיחתי בנויה כרשימת הודעות עם תפקיד (role) מוגדר לכל אחת: System — מגדיר את ההתנהגות הכללית והקבועה של המודל. User — מכיל את קלט המשתמש בפועל. Assistant — מכיל תשובות קודמות של המודל עצמו (לצורך שמירת היסטוריית שיחה). למה צריך את זה? ההפרדה בין הרולים אינה רק סמנטית — היא שכבת האמון היחידה שקיימת ל-API. הנחיה שנשלחת כ-System נחשבת מהימנה ובעלת עדיפות; טקסט שנשלח כ-User (ובפרט טקסט שמקורו במשתמש קצה או במסמך חיצוני) חייב להיחשב פוטנציאלית עוין. בלבול בין הרולים — למשל הזרמת תוכן חיצוני לא-מהימן לתוך ה-System Prompt — פותח פרצת prompt inje"}, {"file": "02-llm-apis-prompts.html", "chapter": "2. LLM APIs ו-Prompt Engineering", "icon": "fa-plug", "id": "prompt-formula", "title": "נוסחת Prompt טוב", "text": "נוסחת Prompt טוב מה זה? נוסחה מעשית לבניית prompt איכותי המורכבת מארבעה רכיבים: Role — מיהו המודל בהקשר הזה. Task — מה בדיוק נדרש לבצע. Constraints — מגבלות פורמט, אורך, טון, איסורים. Context — מידע רקע נדרש לביצוע המשימה. למה צריך את זה? prompt שנכתב כבקשה חופשית וכללית (\"תעזור לי עם המתכון הזה\") משאיר למודל להחליט החלטות פורמט וטון שהאפליקציה צריכה לשלוט בהן. נוסחה מובנית הופכת כתיבת prompt מאמנות אינטואיטיבית לתהליך הנדסי חוזר, הניתן לבדיקה, לגרסאות (versioning), ולשיפור שיטתי. איך זה עובד? כל רכיב ממלא תפקיד שונה בצמצום מרחב הפלט האפשרי: Role — ממסגר את \"קול\" ואת נקודת המבט של התשובה. Task"}, {"file": "02-llm-apis-prompts.html", "chapter": "2. LLM APIs ו-Prompt Engineering", "icon": "fa-plug", "id": "context-engineering", "title": "Context Engineering", "text": "Context Engineering מה זה? הדיסציפלינה של בחירה, סינון וארגון המידע שמוזרם בפועל לתוך ה-Context (ראו Context Window בפרק 1 ) בכל קריאת API — היסטוריית שיחה, תוצאות אחזור, פלטי כלים, ומסמכי רקע — בנפרד מניסוח ה-prompt עצמו. למה צריך את זה? כתיבת prompt קובעת מה מבקשים מהמודל; Context Engineering קובעת עם אילו נתונים הוא עובד. שני הכשלים הנפוצים ביותר בפרודקשן — תשובה לא רלוונטית ותשובה יקרה מדי — נובעים כמעט תמיד מניהול הקשר לקוי, לא מניסוח prompt גרוע. זו הסיבה שהתחום הפך לתפקיד הנדסי נפרד, נבדל מ\"prompt engineering\" הצר. איך זה עובד? Prompt Builder (ראו נושא #1) אחראי בפועל ליישום Context Eng"}, {"file": "02-llm-apis-prompts.html", "chapter": "2. LLM APIs ו-Prompt Engineering", "icon": "fa-plug", "id": "few-shot-cot", "title": "Zero-Shot, Few-Shot ו-Chain-of-Thought", "text": "Zero-Shot, Few-Shot ו-Chain-of-Thought מה זה? שלוש טכניקות ניסוח משימה למודל: Zero-Shot — מבקש ביצוע ישיר ללא דוגמאות. Few-Shot — מצרף מספר דוגמאות קלט-פלט לפני הבקשה עצמה כדי להדגים את הפורמט או ההיגיון הרצוי. Chain-of-Thought (CoT) — מבקש מהמודל לפרט את שלבי ההיגיון בטקסט לפני מתן התשובה הסופית. למה צריך את זה? בחירת הטכניקה הנכונה משפיעה ישירות על איכות, עלות, ולטנסי: Few-Shot — מיותר ומייקר משימות טריוויאליות; היעדרו במשימות עם פורמט לא-סטנדרטי מוביל לפלט לא-עקבי. CoT — משפר דיוק במשימות היגיון רב-שלבי אך מכפיל טוקנים ולעיתים אינו נחוץ כלל למשימות פשוטות. איך זה עובד? Zero-Shot — מתאים למש"}, {"file": "02-llm-apis-prompts.html", "chapter": "2. LLM APIs ו-Prompt Engineering", "icon": "fa-plug", "id": "structured-output", "title": "Structured Output", "text": "Structured Output מה זה? הכפפת פלט המודל לסכמה מוגדרת מראש במקום טקסט חופשי — באמצעות JSON mode, function-calling schemas (המודל \"בוחר\" לקרוא לפונקציה עם ארגומנטים מובנים), או אימות מול מודל טיפוסים כגון Pydantic (Python) או Zod (TypeScript). למה צריך את זה? כאשר הפלט מיועד לצריכה על ידי מערכת (מסד נתונים, API, קוד) ולא לקריאה אנושית, טקסט חופשי הוא ייצוג לא-אמין: כל שינוי קל בניסוח שובר parsing מבוסס regex. Structured Output הופך את הפלט לחוזה (contract) בין המודל למערכת, וניתן לאמת אותו אוטומטית לפני שימוש. איך זה עובד? הבקשה ל-API כוללת סכמה (JSON Schema או מקבילה) המתארת שדות, טיפוסים, ושד"}, {"file": "02-llm-apis-prompts.html", "chapter": "2. LLM APIs ו-Prompt Engineering", "icon": "fa-plug", "id": "output-validation", "title": "Output Validation", "text": "Output Validation מה זה? שכבת בדיקה טכנית שרצה על כל פלט LLM לפני שהוא נכתב למסד נתונים או מוזן למערכת production — מוודאת JSON תקין (parse מצליח), קיום כל השדות הנדרשים, וטיפוסי נתונים נכונים (מחרוזת, מספר, enum תקין). למה צריך את זה? לעולם אין להכניס פלט LLM ישירות למסד נתונים או למערכת production ללא אימות. גם עם Structured Output, פלט המודל נשאר תוצר הסתברותי (ראו Hallucinations בפרק 1) שעלול לחרוג מהסכמה, להכיל ערך לא-הגיוני, או להיכשל בפורמט. Validation היא רשת הביטחון הדטרמיניסטית היחידה סביב רכיב הסתברותי מטבעו. איך זה עובד? שכבת Validation פועלת בשלושה שלבים: (1) parse — ניסיון לפענח "}, {"file": "02-llm-apis-prompts.html", "chapter": "2. LLM APIs ו-Prompt Engineering", "icon": "fa-plug", "id": "prompt-chaining", "title": "Prompt Chaining", "text": "Prompt Chaining מה זה? שרשור מספר קריאות LLM עוקבות, כאשר פלט קריאה אחת משמש כקלט לקריאה הבאה, לעומת ניסיון לפתור את כל המשימה בקריאה מורכבת אחת עם prompt ארוך ורב-שלבי. למה צריך את זה? משימה יחידה מורכבת (למשל \"חלץ מתכון, תרגם אותו, וסווג לקטגוריה\") שנדחסת ל-prompt אחד מגדילה סיכון לכשל חלקי בלתי-ניתן לניפוי — קשה לדעת איזה שלב נכשל. שרשור מפצל את המשימה לקריאות ממוקדות שכל אחת ניתנת לבדיקה, ל-Validation, ולטיפול שגיאות בנפרד. איך זה עובד? כל קריאה בשרשרת מקבלת prompt ממוקד ופלט מאומת מהשלב הקודם, ומבצעת שלב אחד בלבד. העלות היא לטנסי ועלות API גבוהים יותר (מספר קריאות במקום אחת); התועלת היא ד"}, {"file": "02-llm-apis-prompts.html", "chapter": "2. LLM APIs ו-Prompt Engineering", "icon": "fa-plug", "id": "real-world-example", "title": "Real World Example", "text": "Real World Example GitHub Copilot / Cursor עוזרי קוד כמו GitHub Copilot ו-Cursor ממחישים כיצד שלושה מושגי הפרק פועלים יחד במערכת production. כל בקשת עריכה מנוסחת פנימית לפי נוסחת ה-prompt (Role: \"עוזר תכנות מומחה בשפת הפרויקט\", Task: \"בצע את השינוי המבוקש\", Constraints: \"החזר diff מובנה בלבד\", Context: קטעי הקוד הרלוונטיים שנבחרו על ידי Context Engineering — לא הריפו כולו). התשובה חוזרת כ-Structured Output — patch/diff מובנה, לא טקסט חופשי — ועוברת Validation טכני (בדיקת syntax, קיום הקבצים המוזכרים) לפני שהעריכה מוצגת למשתמש להשוואה וקבלה. כשמדובר בשינוי רב-קבצים, המערכת עשויה להפעיל Prompt C"}, {"file": "03-memory-rag.html", "chapter": "3. Memory & RAG", "icon": "fa-database", "id": "conversation-memory", "title": "Conversation Memory", "text": "Conversation Memory מה זה? המנגנון שבו ה-Backend שומר את היסטוריית השיחה בין המשתמש למערכת, ובוחר בכל קריאת API מחדש אילו הודעות מתוך ההיסטוריה הזו לצרף לבקשה הנוכחית כרשימת messages עם roles של User ו-Assistant (ראו System / User / Assistant Roles בפרק 2 ). למה צריך את זה? מכיוון שהמודל עצמו stateless, \"זיכרון שיחה\" הוא אשליה מהונדסת — אין תהליך רץ ברקע שזוכר. אם ה-Backend לא ישלח מחדש בכל קריאה את ההודעות הרלוונטיות מהשיחה עד כה, המודל יתייחס לכל הודעה כפנייה ראשונה ומבודדת, ללא כל מודעות למה שנאמר קודם. תחושת ה\"שיחה הרציפה\" שחווה משתמש בצ'אט היא תוצר של ניהול היסטוריה בצד השרת, לא יכולת מוב"}, {"file": "03-memory-rag.html", "chapter": "3. Memory & RAG", "icon": "fa-database", "id": "rag-flow", "title": "תזרים RAG", "text": "תזרים RAG מה זה? Retrieval-Augmented Generation (RAG) הוא תבנית ארכיטקטונית שבה, לפני קריאה ל-LLM, המערכת מאחזרת מסמכים רלוונטיים ממאגר ידע חיצוני ומצרפת אותם להקשר — כך שהמודל עונה בהתבסס על מידע ספציפי ועדכני, לא רק על מה שנלמד באימון. למה צריך את זה? ידע האימון של מודל קפוא בזמן (ראו Inference לעומת Training בפרק 1 ) ואינו כולל מידע פרטי, עסקי, או שהתעדכן לאחר מועד האימון. RAG פותר את הפער הזה ללא צורך לאמן מחדש את המודל: המידע הרלוונטי מסופק כטקסט בתוך ה-Context בזמן הבקשה, מה שגם מצמצם הזיות (ראו Hallucinations בפרק 1 ) כי המודל \"מצטט\" מתוך מקור נתון במקום להסתמך על שחזור מהזיכרון הפנימי "}, {"file": "03-memory-rag.html", "chapter": "3. Memory & RAG", "icon": "fa-database", "id": "memory-manager", "title": "Memory Manager", "text": "Memory Manager מה זה? הרכיב האחראי להחליט, בכל קריאת API, אילו הודעות עבר או עובדות שנלמדו במהלך השיחה נכנסות בפועל ל-Context — באמצעות בחירת ה-N ההודעות האחרונות, סיכום (summarization) של היסטוריה ארוכה, או שילוב של השניים. למה צריך את זה? שיחה ארוכה שנשלחת גולמית וללא סינון חורגת מ-Context Window או הופכת יקרה מדי לכל קריאה בודדת. Memory Manager הוא מה שמאפשר לשיחה \"להימשך\" לאורך זמן בעלות סבירה. איך זה עובד? אסטרטגיה נפוצה: לשמור את ה-N ההודעות האחרונות במלואן, ולסכם (באמצעות קריאת LLM נפרדת) את כל מה שקדם להן לפסקת תקציר קצרה שמצורפת כהקשר רקע. דוגמה לאחר עשרות הודעות בשיחה תמיכה ארוכה, Me"}, {"file": "03-memory-rag.html", "chapter": "3. Memory & RAG", "icon": "fa-database", "id": "token-budgeting", "title": "Token Budgeting", "text": "Token Budgeting מה זה? חלוקה מכוונת ומוגבלת מראש של תקציב הטוקנים העומד לרשות קריאת API בין רכיביו: System Prompt, Memory (היסטוריית שיחה), RAG (מסמכים מאוחזרים), ורזרבה לתשובה הצפויה. למה צריך את זה? Context Window סופי, ומחיר קריאה נגזר ישירות ממספר הטוקנים הנשלחים (ראו תמחור בפרק 1 ). ללא תקציב מוגדר, רכיב אחד (למשל היסטוריה ארוכה) עלול \"לבלוע\" את כל המקום ולדחוק החוצה מידע קריטי כמו מסמכי RAG, ולפגוע גם באיכות וגם בעלות. איך זה עובד? Prompt Builder מקצה תקרת טוקנים לכל רכיב מראש (למשל: System קבוע, עד X טוקנים ל-Memory, עד Y ל-RAG), וכל רכיב שחורג מתקרתו נחתך או מסוכם לפני ההרכבה הסופית של"}, {"file": "03-memory-rag.html", "chapter": "3. Memory & RAG", "icon": "fa-database", "id": "embeddings", "title": "Embeddings", "text": "Embeddings מה זה? Embedding הוא וקטור של מספרים (בדרך כלל מאות עד אלפי ממדים) שמייצג את המשמעות הסמנטית של טקסט (או תוכן אחר), כך שטקסטים בעלי משמעות דומה מקבלים וקטורים הממוקמים קרוב זה לזה במרחב הרב-ממדי. למה צריך את זה? מחשבים לא יכולים להשוות \"משמעות\" של טקסט ישירות. embeddings הופכים משמעות למספרים שניתן להשוות ביניהם מתמטית — זו התשתית שמאפשרת חיפוש \"לפי משמעות\" (semantic search) במקום התאמת מילות מפתח בלבד, ועליה מבוסס כל תזרים RAG. איך זה עובד? מודל embedding ייעודי (נפרד ממודל השיחה) מקבל טקסט ומחזיר וקטור קבוע-אורך. מודלים אלו מאומנים כך שטקסטים הדומים מבחינה סמנטית — גם אם משתמשים ב"}, {"file": "03-memory-rag.html", "chapter": "3. Memory & RAG", "icon": "fa-database", "id": "vector-db-basics", "title": "יסודות Vector DB", "text": "יסודות Vector DB מה זה? מסד נתונים וקטורי הוא מסד נתונים המתמחה באחסון embeddings וביצוע חיפוש דמיון (similarity search) מהיר ביניהם בקנה מידה — איתור, מתוך מיליוני וקטורים, אלו הקרובים ביותר לוקטור שאילתה נתון. למה צריך את זה? חיפוש דמיון מדויק (השוואת וקטור מול כל וקטור במאגר) הופך איטי מדי כשמדובר במאגר גדול. מסד נתונים וקטורי מספק מבני אינדוקס ייעודיים המאפשרים חיפוש דמיון קרוב-לוודאי (approximate) במהירות גבוהה, גם כשהמאגר מכיל מיליוני פריטים — זו התשתית שמאפשרת לשלב Vector Search של RAG לרוץ בזמן סביר. איך זה עובד? בשלב האינדוקס, כל מסמך (או קטע ממנו) מומר ל-embedding ונשמר במסד יחד עם ה"}, {"file": "03-memory-rag.html", "chapter": "3. Memory & RAG", "icon": "fa-database", "id": "cosine-similarity", "title": "Cosine Similarity", "text": "Cosine Similarity מה זה? מדד דמיון בין שני וקטורים, המחושב מהזווית ביניהם (קוסינוס הזווית) ולא ממרחקם המוחלט — ערך קרוב ל-1 מציין וקטורים כמעט זהים בכיוונם, ערך קרוב ל-0 מציין חוסר קשר. למה צריך את זה? ל-embeddings, כיוון הוקטור נושא את המשמעות הסמנטית, בעוד גודלו (magnitude) לרוב מושפע מגורמים כמו אורך הטקסט המקורי ואינו רלוונטי לדמיון. Cosine Similarity מתעלמת מהגודל ומודדת רק כיוון — ולכן היא המדד המקובל ביותר להשוואת embeddings, בהבדל ממדדי מרחק כמו מרחק אוקלידי הרגישים גם לגודל הוקטור. איך זה עובד? מסד הנתונים הוקטורי מחשב את Cosine Similarity בין וקטור השאילתה לבין כל וקטור מועמד (או קיר"}, {"file": "03-memory-rag.html", "chapter": "3. Memory & RAG", "icon": "fa-database", "id": "rag-vs-finetune", "title": "RAG מול Fine-Tuning", "text": "RAG מול Fine-Tuning מה זה? שתי גישות שונות מהותית להתאמת מודל למשימה ספציפית: RAG — מזין ידע חיצוני להקשר בזמן הבקשה מבלי לשנות את המודל עצמו. Fine-Tuning — מאמן מחדש (חלקית) את משקלי המודל כך שהתנהגותו, סגנונו, או דפוסי הפלט שלו משתנים באופן קבוע. למה צריך את זה? בחירה שגויה בין השניים היא כשל ארכיטקטוני יקר: Fine-Tuning על ידע שמתעדכן תדיר מחייב אימון מחדש בכל שינוי. RAG לשינוי סגנון או פורמט קבוע דורש חזרה על אותה הנחיה בכל פרומפט ואינו אמין באותה מידה כמו התנהגות \"צרובה\" במודל. איך זה עובד? כלל ההכרעה המעשי: RAG — כאשר הצורך הוא ידע — עובדות, מסמכים, מידע שמשתנה או מתעדכן — מכיוון שעדכון מ"}, {"file": "03-memory-rag.html", "chapter": "3. Memory & RAG", "icon": "fa-database", "id": "real-world-example", "title": "Real World Example", "text": "Real World Example Claude / ChatGPT — Memory ואחזור מקורות עוזרים שיחתיים כמו Claude ו-ChatGPT ממחישים כיצד שני מנגנוני הפרק פועלים זה לצד זה. שכבת Conversation Memory שומרת את היסטוריית הצ'אט ומחליטה, בכל תגובה, אילו הודעות קודמות לצרף מחדש לקריאת ה-API — כולל, במוצרים מסוימים, שכבת Memory Manager שמסכמת שיחות ישנות או שומרת עובדות נבחרות לטווח ארוך במקום להזרים תמלול גולמי אינסופי. כאשר משתמש מבקש מידע עדכני או מבוסס-מקור — למשל שאלה שדורשת חיפוש רשת — המערכת מפעילה תבנית דמוית-RAG: היא מאחזרת תוצאות רלוונטיות ממקור חיצוני, מצרפת אותן להקשר, ורק אז מנסחת תשובה עם ציון המקורות שממנה נשאבה — ב"}, {"file": "04-advanced-rag.html", "chapter": "4. RAG מתקדם", "icon": "fa-layer-group", "id": "chunking", "title": "אסטרטגיות Chunking", "text": "אסטרטגיות Chunking מה זה? Chunking הוא חלוקת מסמכים ארוכים ליחידות טקסט קטנות יותר (\"chunks\") לפני הפקת embeddings עבורן. שלוש גישות נפוצות: fixed-size — חלוקה קבועה לפי מספר תווים או טוקנים, ללא התחשבות בתוכן. recursive — חלוקה היררכית שמנסה לשמור על גבולות מבניים טבעיים (פסקאות, ואם לא ניתן — משפטים, ואם לא — מילים). semantic — חלוקה לפי גבולות משמעות בפועל, על ידי מדידת דמיון embeddings בין משפטים סמוכים ופיצול במקום שבו הדמיון צונח. למה צריך את זה? מסמך שלם ארוך מדי לאחסון כ-embedding יחיד בעל משמעות — embedding אחד ל\"מסמך\" של עשרות עמודים ממוצע את כל התכנים שבו וקהה כמעט לכל שאילתה ספציפי"}, {"file": "04-advanced-rag.html", "chapter": "4. RAG מתקדם", "icon": "fa-layer-group", "id": "hybrid-search", "title": "Hybrid Search", "text": "Hybrid Search מה זה? שילוב שני סוגי חיפוש במקביל על אותו מאגר: BM25 — אלגוריתם דירוג סטטיסטי מבוסס התאמת מילות מפתח (גרסה משוכללת של TF-IDF). חיפוש וקטורי — דמיון סמנטי מבוסס embeddings (ראו Embeddings בפרק 3 ). תוצאות שני החיפושים ממוזגות לדירוג אחד משולב. למה צריך את זה? לכל שיטה יש עיוורון משלים. חיפוש וקטורי מצטיין בתפיסת משמעות גם כשהניסוח שונה לגמרי, אך מפספס לעיתים התאמות מדויקות וקריטיות — שם מוצר ספציפי, מספר סידורי, קוד שגיאה — כי אלו מוטמעים ב-embedding כחלק ממשמעות כללית ולא כזיהוי מדויק. BM25, לעומת זאת, תופס בדיוק את ההתאמות המילוליות המדויקות הללו אך אינו \"מבין\" נרדפות או ניסוח "}, {"file": "04-advanced-rag.html", "chapter": "4. RAG מתקדם", "icon": "fa-layer-group", "id": "reranking", "title": "Reranking", "text": "Reranking מה זה? שלב סינון שני, שמתבצע אחרי אחזור ראשוני (וקטורי, BM25, או hybrid), שבו מודל ייעודי — cross-encoder — בוחן כל זוג שאילתה-מסמך יחד באופן ישיר, ומדרג מחדש את המועמדים לפי רלוונטיות מדויקת יותר, לפני שרק חלק קטן מהם (למשל 3-5 המובילים) נשלח בפועל ל-LLM. למה צריך את זה? חיפוש וקטורי (bi-encoder) מקודד את השאילתה ואת המסמכים בנפרד לוקטורים ומשווה ביניהם — יעיל וקטן חישובית, אך גס: הוא לא \"רואה\" את השאילתה והמסמך יחד, רק את הקרבה בין שני ייצוגים שנוצרו בנפרד. Cross-encoder, לעומת זאת, מזין את זוג הטקסטים יחד למודל אחד שמייצר ציון רלוונטיות ישיר — מדויק משמעותית, אך יקר מדי להרצה על כ"}, {"file": "04-advanced-rag.html", "chapter": "4. RAG מתקדם", "icon": "fa-layer-group", "id": "vector-db-comparison", "title": "השוואת Vector DB", "text": "השוואת Vector DB מה זה? ארבע משפחות פתרונות נפוצות למסד נתונים וקטורי (ראו יסודות Vector DB בפרק 3 ): Pinecone, Weaviate, pgvector, ו-Chroma — כל אחד עם מיצוב ארכיטקטוני שונה מהותית, לא רק הבדלי תכונות שטחיים. למה צריך את זה? בחירת Vector DB היא החלטת תשתית עם השלכות ארוכות-טווח על תפעול, עלות תחזוקה, ומורכבות המערכת — לא רק על מהירות חיפוש. התאמה בין אופי הפרויקט (סטאק קיים, היקף נתונים, שלב פיתוח) לבין מיצוב הפתרון חשובה יותר מהשוואת benchmarks נקודתית. איך זה עובד? ההבדל המרכזי בין הפתרונות הוא ציר Hosting (מנוהל לחלוטין מול self-hosted) וציר יעד השימוש (פרוטוטייפ קליל מול מערכת production "}, {"file": "04-advanced-rag.html", "chapter": "4. RAG מתקדם", "icon": "fa-layer-group", "id": "query-transformation", "title": "Query Transformation", "text": "Query Transformation מה זה? משפחת טכניקות לשיפור שאילתת החיפוש עצמה, לפני שהיא נשלחת לאחזור, באמצעות LLM. שתי הטכניקות המרכזיות: HyDE (Hypothetical Document Embeddings) — יצירת מסמך \"תשובה\" היפותטי ודמיוני על ידי LLM, וחיפוש לפי ה-embedding של המסמך ההיפותטי הזה במקום לפי השאלה המקורית. Multi-Query — יצירת כמה ניסוחים שונים לאותה שאלה על ידי LLM, והרצת חיפוש עם כולם במקביל. למה צריך את זה? שאלה קצרה בשפה טבעית (\"איך מגדירים timeout?\") שונה מבנית ממסמך תשובה אמיתי (\"כדי להגדיר timeout, יש לקבוע את הפרמטר...\"), ולכן ה-embedding שלה עלול להיות רחוק במרחב הוקטורי מה-embedding של המסמך הרלוונטי ביו"}, {"file": "04-advanced-rag.html", "chapter": "4. RAG מתקדם", "icon": "fa-layer-group", "id": "agentic-rag-preview", "title": "Agentic RAG", "text": "Agentic RAG מה זה? תבנית שבה retrieval הופך מ-שלב קבוע שמתבצע אוטומטית בתחילת כל תשובה, לכלי (tool) שה-Agent בוחר בעצמו מתי ואיך להפעיל. למה צריך את זה? לא כל שאלה דורשת אחזור, ולעיתים נדרשים כמה סבבי אחזור מדורגים לפני שיש מספיק מידע לענות — retrieval קבוע-מראש לא מתאים לשני המקרים הללו. איך זה עובד? ה-Agent מקבל retrieval כאחד מכלי ה-tools העומדים לרשותו, ומחליט בכל צעד בתהליך ההיגיון שלו האם, מתי, ובאיזו שאילתה לקרוא לו — בדיוק כמו כל tool אחר. דוגמה Agent שנשאל שאלה מורכבת עשוי לבצע אחזור ראשוני, לגלות שהתשובה חלקית, ולבצע אחזור נוסף ממוקד יותר לפני שהוא מנסח תשובה סופית — במקום אחזור בודד"}, {"file": "04-advanced-rag.html", "chapter": "4. RAG מתקדם", "icon": "fa-layer-group", "id": "rag-eval-preview", "title": "הערכת איכות RAG", "text": "הערכת איכות RAG מה זה? בדיקת איכות פייפליין RAG לאורך שני צירים נפרדים: faithfulness — האם התשובה נאמנה למסמכים שאוחזרו בפועל. relevance — האם המסמכים שאוחזרו רלוונטיים לשאלה מלכתחילה. למה צריך את זה? תשובה טובה יכולה להיכשל בשני מקומות נפרדים — אחזור גרוע (מסמכים לא-רלוונטיים) או generation גרוע (התעלמות מהמסמכים שכן אוחזרו) — ובלי למדוד את שניהם בנפרד אי אפשר לדעת איפה לתקן. איך זה עובד? relevance נמדדת ברמת שלב האחזור בלבד, בלי קשר לתשובה הסופית; faithfulness נמדדת בהשוואה בין תוכן התשובה לתוכן המסמכים שסופקו כהקשר, בדרך כלל באמצעות LLM-as-judge. דוגמה מערכת עשויה לאחזר מסמכים רלוונטיים מאו"}, {"file": "04-advanced-rag.html", "chapter": "4. RAG מתקדם", "icon": "fa-layer-group", "id": "real-world-example", "title": "Real World Example", "text": "Real World Example Cursor / GitHub Copilot — פייפליין codebase-retrieval כלי עריכת קוד מבוססי AI כמו Cursor ו-GitHub Copilot ממחישים כיצד כל נושאי הפרק פועלים יחד בפייפליין אחד. בשלב האינדוקס, בסיס הקוד עובר chunking מודע-מבנה שמכבד גבולות של פונקציות ומחלקות במקום חיתוך שרירותי. כשהמשתמש שואל שאלה או מבקש שינוי, המערכת מריצה חיפוש היברידי — התאמת מילות מפתח מדויקת לשמות פונקציות ומשתנים לצד חיפוש סמנטי לכוונה הכללית — ומצמצמת סט מועמדים רחב. שלב reranking בוחן את המועמדים יחד עם השאילתה ומדרג מחדש כדי שרק קטעי הקוד הרלוונטיים ביותר באמת יגיעו להקשר. במקרים מורכבים יותר, הכלי פועל באופן Agenti"}, {"file": "05-agents.html", "chapter": "5. Agents & Modern AI", "icon": "fa-robot", "id": "function-calling", "title": "Function Calling", "text": "Function Calling מה זה? יכולת של LLM להחזיר, במקום תשובת טקסט חופשי, פלט מובנה המייצג קריאה לפונקציה — שם הפונקציה ופרמטרים תואמי-schema — כדי שקוד צד-לקוח יריץ אותה בפועל. המודל עצמו אינו מריץ קוד; הוא רק מפיק את הבקשה המובנית, וקוד חיצוני מבצע אותה ומחזיר את התוצאה חזרה למודל. למה צריך את זה? טקסט חופשי אינו ניתן לביצוע אוטומטי באופן אמין — פענוח בקשה כמו \"תבדוק את מזג האוויר בתל אביב\" מתוך פרוזה חופשית דורש parsing שביר ורגיש לניסוח. function calling פותר את זה בשורש: המודל מאומן ו/או מונחה להפיק JSON תואם-schema קבוע מראש, כך שקוד צד-לקוח יכול לסמוך על המבנה ולהריץ אותו ישירות בלי היסק לשו"}, {"file": "05-agents.html", "chapter": "5. Agents & Modern AI", "icon": "fa-robot", "id": "tool-calling", "title": "Tool Calling", "text": "Tool Calling מה זה? הרחבה מעשית של function calling: המודל מקבל רשימת \"כלים\" זמינים, כל אחד עם schema משלו, ובוחר בעצמו איזה כלי (אם בכלל) להפעיל ומתי — כחלק מתהליך רב-שלבי, לא כקריאה בודדת. למה צריך את זה? משימות אמיתיות דורשות שילוב של יכולות שונות — חיפוש, חישוב, קריאה למסד נתונים — והמודל צריך להחליט לבד אילו מהן רלוונטיות לבקשה נתונה, בסדר הנכון. איך זה עובד? כל הכלים מוגדרים מראש בקריאת ה-API; המודל בוחר כלי (או אף אחד, אם תשובת טקסט ישירה מספיקה), מקבל את התוצאה, ולעיתים בוחר כלי נוסף בהתבסס עליה — לולאה שמתוארת בהרחבה בנושא Agent Loop . דוגמה כלים agentic לכתיבת קוד כמו Cursor ו-GitHub"}, {"file": "05-agents.html", "chapter": "5. Agents & Modern AI", "icon": "fa-robot", "id": "agent-loop", "title": "Agent Loop", "text": "Agent Loop מה זה? מבנה הבקרה שהופך tool calling מקריאה חד-פעמית לתהליך איטרטיבי: בקשת המשתמש עוברת תכנון, הפעלת כלים, קריאה חוזרת ל-LLM עם התוצאות, וחזרה על הצעד הזה עד שיש מספיק מידע לתשובה סופית. למה צריך את זה? משימות מורכבות אינן נפתרות בקריאת כלי בודדת — לעיתים תוצאת כלי אחד חושפת שנדרש כלי נוסף, או שהתוצאה חלקית ודורשת ניסוח מחדש. לולאה מאפשרת למודל להגיב לתוצאות ביניים במקום להתחייב מראש לרצף פעולות קבוע. איך זה עובד? הבקשה נכנסת, שלב תכנון (מפורש או מרומז בתוך המודל עצמו) קובע איזו פעולה נדרשת, כלי מופעל, התוצאה חוזרת ל-LLM כהקשר נוסף, וה-LLM מחליט אם יש מספיק מידע לתשובה סופית או שנדר"}, {"file": "05-agents.html", "chapter": "5. Agents & Modern AI", "icon": "fa-robot", "id": "multi-agent-intro", "title": "מבוא ל-Multi-Agent", "text": "מבוא ל-Multi-Agent מה זה? מערכות שבהן כמה agents מתמחים משתפים פעולה על אותה משימה, במקום agent כללי בודד — לדוגמה agent אחד שמתכנן, אחד שמבצע, ואחד שבודק את התוצאה. למה צריך את זה? agent בודד עם prompt כללי מדי נוטה להתפזר במשימות מורכבות ורב-תחומיות. פיצול לתפקידים מתמחים — כל אחד עם prompt, כלים, ולעיתים אף מודל מותאמים לתפקידו — משפר מיקוד ואיכות, במחיר מורכבות תזמור נוספת. איך זה עובד? כל אחד רץ כתהליך עצמאי יחסית עם תחום אחריות מוגדר: Agent מתכנן — מפרק את המשימה לתת-משימות. Agent מבצע — מריץ אותן (כולל agent loop משלו). Agent בודק — מאמת את התוצאה לפני מסירתה למשתמש או חזרה לתיקון. דוגמ"}, {"file": "05-agents.html", "chapter": "5. Agents & Modern AI", "icon": "fa-robot", "id": "mcp", "title": "MCP — Model Context Protocol", "text": "MCP — Model Context Protocol מה זה? פרוטוקול אחיד לחיבור כלים ומקורות מידע חיצוניים למודלים, במקום אינטגרציה מותאמת-אישית לכל שילוב כלי-מודל בנפרד. למה צריך את זה? בלי פרוטוקול אחיד, חיבור M כלים ל-N מודלים שונים דורש עד M×N אינטגרציות נפרדות — כל כלי חדש דורש עבודת אינטגרציה מול כל מודל, וכל מודל חדש דורש עבודה מול כל כלי קיים. MCP הופך את זה לבעיה לינארית: כלי שמדבר MCP זמין לכל מודל שתומך ב-MCP, וכל מודל שתומך ב-MCP יכול לדבר עם כל כלי כזה, ללא קוד אינטגרציה ייעודי לכל זוג. איך זה עובד? שרת MCP חושף ממשק אחיד — רשימת כלים, מקורות מידע, ו-schema מוגדר — וכל לקוח (סביבת agent, כלי עריכה, אפלי"}, {"file": "05-agents.html", "chapter": "5. Agents & Modern AI", "icon": "fa-robot", "id": "vision", "title": "Vision — קלט חזותי", "text": "Vision — קלט חזותי מה זה? יכולת של מודל multimodal לעבד תמונה כקלט לצד טקסט — לקדד את התוכן החזותי לייצוג שהמודל יכול לנמק לגביו יחד עם שאר ההקשר של השיחה. למה צריך את זה? הרבה משימות מתחילות בקלט שאינו טקסטואלי מטבעו — צילום מסך של שגיאה, תרשים, טופס סרוק. תיאור מילולי של תמונה על ידי המשתמש מאבד מידע ודורש מאמץ; קלט חזותי ישיר מאפשר למודל לנמק ישירות על התוכן כפי שהוא. איך זה עובד? התמונה עוברת קידוד ויזואלי — רכיב ייעודי שממיר את הפיקסלים לייצוג שהמודל השפתי יכול לעבד. הייצוג הזה משולב לתוך ה-Context יחד עם הטקסט, כך שהמודל מנמק על שניהם באותו תהליך הסקה אחד, ולא כשני שלבים נפרדים. Image קל"}, {"file": "05-agents.html", "chapter": "5. Agents & Modern AI", "icon": "fa-robot", "id": "reasoning-models", "title": "מודלי Reasoning", "text": "מודלי Reasoning מה זה? מודלים בעלי \"חשיבה מורחבת\" (extended thinking / reasoning tokens) המבצעים תהליך חשיבה פנימי — פירוק הבעיה, בדיקת חלופות, תיקון עצמי — לפני הפקת התשובה הסופית המוצגת למשתמש. למה צריך את זה? בעיות מורכבות רב-שלביות — הוכחה מתמטית, ניתוח לוגי מרובה-תנאים, תכנון עם תלויות — נהנות מתהליך חשיבה מפורש שמאפשר למודל לבדוק ולתקן את עצמו לפני שהוא \"מתחייב\" לתשובה. עבור משימות פשוטות ועובדתיות, אותו תהליך חשיבה מוסיף latency ועלות ללא שיפור תואם באיכות התשובה — היתרון תלוי-משימה, לא גורף. איך זה עובד? לפני הפקת התשובה הגלויה, המודל מייצר רצף \"מחשבה\" פנימי שאינו בהכרח מוצג למשתמש במל"}, {"file": "05-agents.html", "chapter": "5. Agents & Modern AI", "icon": "fa-robot", "id": "real-world-example", "title": "Real World Example", "text": "Real World Example Cursor Agent Mode / GitHub Copilot Workspace — לולאת agent מלאה מצב agentic בכלי כתיבת קוד כמו Cursor או GitHub Copilot Workspace ממחיש כיצד כל נושאי הפרק פועלים יחד. הבקשה (\"הוסף endpoint חדש שמאמת טוקן ומחזיר פרופיל משתמש\") נכנסת ללולאת Agent Loop : שלב תכנון מפרק אותה לתת-משימות — איתור קובץ ה-routes הרלוונטי, בדיקת מנגנון האימות הקיים, כתיבת הקוד החדש, הרצת בדיקות. כל תת-משימה מופעלת דרך tool calling — קריאת קובץ, חיפוש בבסיס קוד, כתיבת קובץ, הרצת terminal — כאשר כל קריאה בנויה על מנגנון function calling הבסיסי. אם צילום מסך של שגיאת בדיקה מצורף, הכלי מעבד אותו דרך ערוץ "}, {"file": "06-agent-patterns.html", "chapter": "6. Agent Patterns מתקדמים", "icon": "fa-sitemap", "id": "react-pattern", "title": "דפוס ReAct (Reasoning + Acting)", "text": "דפוס ReAct (Reasoning + Acting) מה זה? דפוס שבו המודל מנמק במפורש בטקסט (Thought) לפני כל פעולה (Action), צופה בתוצאה שחוזרת (Observation), ומשתמש בה כקלט לסבב הנימוק הבא — Thought → Action → Observation, שוב ושוב, עד שיש מספיק מידע לתשובה סופית. למה צריך את זה? Agent Loop הבסיסי מתאר את מבנה הבקרה (בקשה → כלי → תוצאה → החלטה) אבל לא כופה שום מבנה על ההחלטה עצמה. בלי נימוק גלוי, בחירת הפעולה הבאה היא \"קופסה שחורה\" — קשה לדבג למה agent בחר כלי מסוים, וקשה למודל עצמו לתקן מסלול שגוי כי אין רצף מחשבה מפורש שהוא יכול \"להסתכל עליו\" בסבב הבא. כתיבת Thought מפורש לפני Action משפרת עקביות ההחלטה וגם ה"}, {"file": "06-agent-patterns.html", "chapter": "6. Agent Patterns מתקדמים", "icon": "fa-sitemap", "id": "plan-and-execute", "title": "Plan-and-Execute", "text": "Plan-and-Execute מה זה? דפוס שבו שלב תכנון נפרד — פירוק המשימה המלאה לרשימת תתי-משימות מראש — קודם לשלב ביצוע, בניגוד ל- ReAct שמתכנן צעד בודד אחד בכל סבב בלי תוכנית כוללת מוקדמת. למה צריך את זה? תכנון צעד-אחר-צעד (כמו ב-ReAct) יעיל וגמיש, אבל במשימות ארוכות עם תלויות ברורות בין שלבים הוא מבזבז סבבי נימוק על גילוי מחדש של מבנה שכבר ידוע מראש. תוכנית מלאה מראש נותנת יעילות וזרימה ברורה — אפשר להריץ תתי-משימות בלי לנמק מחדש על המבנה הכולל בכל סבב. המחיר: פחות גמישות לשינויים באמצע — אם תת-משימה חושפת מידע שמפר הנחת יסוד של התוכנית, נדרש מנגנון תכנון-מחדש מפורש, לא רק \"המשך הלאה\". איך זה עובד? של"}, {"file": "06-agent-patterns.html", "chapter": "6. Agent Patterns מתקדמים", "icon": "fa-sitemap", "id": "reflexion", "title": "Reflexion", "text": "Reflexion מה זה? דפוס שבו ה-agent מבקר את הפלט או הביצוע של עצמו (self-critique) לפני החזרת תוצאה סופית או לפני צעד הבא, ומזין את הביקורת בחזרה כהקשר — למידה מכישלון בתוך אותה ריצה, לא fine-tuning של המודל עצמו. למה צריך את זה? agent שמבצע פעולה ומקבל אותה כמוגמרת ללא בדיקה חוזרת, מעביר טעויות הלאה בלי הזדמנות לתקן. הוספת שלב ביקורת עצמית — \"האם התוצאה הזו באמת עונה על הדרישה? מה חסר?\" — לפני שהתוצאה נחשבת סופית, תופסת כשלים שהמודל עצמו יכול לזהות כשהוא בוחן את הפלט מחדש בפרספקטיבה נפרדת, גם בלי משוב חיצוני. איך זה עובד? לאחר הפקת פלט או ביצוע פעולה, סבב נוסף מפעיל את המודל (או instance נפרד ש"}, {"file": "06-agent-patterns.html", "chapter": "6. Agent Patterns מתקדמים", "icon": "fa-sitemap", "id": "orchestration-patterns", "title": "דפוסי תזמור Multi-Agent", "text": "דפוסי תזמור Multi-Agent מה זה? שני דפוסים מנוגדים לתזמור מערכת multi-agent : Supervisor — agent מרכזי מנתב משימות ל-agents מתמחים ומרכז את תוצאותיהם. Swarm — agents שווי-מעמד המתקשרים ומעבירים שליטה זה לזה ישירות, ללא מתאם מרכזי. למה צריך את זה? ברגע שיש יותר מ-agent אחד, מישהו — או משהו — צריך להחליט מי פועל מתי ומי רואה את מה. Supervisor — נותן שליטה ברורה ונקודת אחריות יחידה על הזרימה, אבל הופך לצוואר בקבוק כאשר כל תקשורת חייבת לעבור דרכו. Swarm — מבזר את ההחלטה ומאפשר תקשורת ישירה בין agents שצריכים לשתף פעולה בצמידות, אך מוותר על נקודת בקרה מרכזית שמפשטת דיבוג ומעקב. איך זה עובד? Supervis"}, {"file": "06-agent-patterns.html", "chapter": "6. Agent Patterns מתקדמים", "icon": "fa-sitemap", "id": "human-in-the-loop", "title": "Human-in-the-Loop", "text": "Human-in-the-Loop מה זה? נקודות עצירה יזומות בתוך agent loop שבהן ה-agent ממתין באופן מפורש לאישור אדם לפני ביצוע פעולה בלתי-הפיכה או רגישה, במקום להמשיך אוטומטית. למה צריך את זה? לא כל טעות ניתנת לתיקון בסבב הבא — מחיקת נתונים, ביצוע תשלום, או שליחת הודעה ללקוח חיצוני הן פעולות שברגע שקרו, קרו. עבור פעולות מהסוג הזה שקיפות וניתנת-לתיקון (כמו reflexion) אינה מספיקה; נדרשת חסימה יזומה של הביצוע עד לאישור מפורש. איך זה עובד? כלים או פעולות מסווגים מראש כ\"דורשי אישור\"; כשה-agent מגיע לקריאה כזו, הלולאה נעצרת, הפעולה המוצעת מוצגת לאדם, וההרצה ממשיכה רק לאחר אישור (או מבוטלת/מותאמת לפי דחייה). דוגמ"}, {"file": "06-agent-patterns.html", "chapter": "6. Agent Patterns מתקדמים", "icon": "fa-sitemap", "id": "agent-error-handling", "title": "טיפול בשגיאות בלולאת Agent", "text": "טיפול בשגיאות בלולאת Agent מה זה? מנגנוני התמודדות עם כשלים בתוך agent loop: ניסיונות חוזרים (retries) עם השהיה גוברת (backoff), timeout לכלים שנתקעים, והחלטה מודעת מתי להיכשל בצורה מבוקרת במקום לנסות שוב ללא סוף. למה צריך את זה? כלים חיצוניים נכשלים — timeouts, שגיאות רשת זמניות, API עמוס. בלי מנגנון טיפול, כשל נקודתי עוצר את כל הריצה או, בקצה השני, agent שממשיך לנסות ללא הגבלה תוקע משאבים ומייצר עלות בלתי-צפויה. איך זה עובד? קריאת כלי שנכשלת מסווגת כזמנית (retry עם backoff מוגבל) או קבועה (fail gracefully — דיווח כשל ברור ל-LLM כדי שינמק על חלופה, במקום לחזור על אותה קריאה). timeout מוגדר לכ"}, {"file": "06-agent-patterns.html", "chapter": "6. Agent Patterns מתקדמים", "icon": "fa-sitemap", "id": "agent-memory", "title": "זיכרון Agent", "text": "זיכרון Agent מה זה? שלושה סוגי זיכרון הרלוונטיים ל-agent: short-term — ה-Context של הריצה הנוכחית בלבד, נעלם בסופה. long-term — מידע כללי המאוחסן חיצונית ונטען לפי צורך בין ריצות נפרדות. episodic — זיכרון של ריצות או משימות ספציפיות קודמות, לשימוש כתקדים במשימה עתידית דומה. למה צריך את זה? short-term בלבד אומר שה-agent \"שוכח\" הכל ברגע שהריצה מסתיימת — כל משימה מתחילה מאפס, גם אם דומה למשימה שכבר נפתרה. long-term ו-episodic מאפשרים לשמר ידע מעבר לריצה בודדת: long-term לעובדות ותצורה יציבה, episodic לתקדימים קונקרטיים (\"איך נפתרה בעיה דומה בעבר\") שיכולים לקצר ריצות עתידיות. איך זה עובד? short-te"}, {"file": "06-agent-patterns.html", "chapter": "6. Agent Patterns מתקדמים", "icon": "fa-sitemap", "id": "real-world-example", "title": "Real World Example", "text": "Real World Example Claude Code / Cursor Agent Mode — שילוב plan-and-execute עם human-in-the-loop כלי agentic לכתיבת קוד ממחיש שילוב טבעי של כמה מהדפוסים שנסקרו בפרק. הבקשה (\"הוסף בדיקות אינטגרציה לפיצ'ר X\") עוברת תחילה שלב plan-and-execute : הכלי מציג תוכנית — אילו קבצים ייבדקו, אילו תרחישים יכוסו — לפני שהוא נוגע בקוד. כל תת-משימה בתוכנית מתבצעת בלולאת ReAct פנימית: נימוק גלוי על הצעד הבא, קריאת כלי, בחינת התוצאה, וחזרה. כשמגיעה פעולה בלתי-הפיכה — מחיקת קובץ בדיקה ישן, למשל, או הרצת פקודת terminal שמשנה תצורה — הריצה עוצרת בנקודת human-in-the-loop ומחכה לאישור מפורש, בעוד עריכות קוד הפיכות וב"}, {"file": "07-evaluation.html", "chapter": "7. Evaluation & Testing", "icon": "fa-flask", "id": "why-evals", "title": "למה בכלל צריך Evals", "text": "למה בכלל צריך Evals מה זה? evals הם תהליך שיטתי ומדיד להערכת איכות פלט של מערכת מבוססת LLM — לא בדיקה ידנית חד-פעמית, אלא סוויטה שאפשר להריץ שוב ושוב ולהשוות תוצאות לאורך זמן. למה צריך את זה? שלוש בעיות ייחודיות ל-LLM מחייבות evals שיטתיים: פלט לא-דטרמיניסטי — אותה שאלה יכולה להניב תשובות שונות בין הרצות, כך שבדיקה חד-פעמית אינה מייצגת התנהגות כללית. שינוי קטן — עדכון prompt, שדרוג גרסת מודל, החלפת ספק — עלול לשפר מקרה אחד ולפגוע בעשרות אחרים בו-זמנית, בלי שאף אחד ישים לב עד שמשתמש מדווח על תקלה. בלי מדידה עקבית אי אפשר לענות על השאלה הבסיסית ביותר של הנדסת AI: האם הגרסה החדשה טובה יותר מהישנה"}, {"file": "07-evaluation.html", "chapter": "7. Evaluation & Testing", "icon": "fa-flask", "id": "llm-as-judge", "title": "LLM-as-Judge", "text": "LLM-as-Judge מה זה? שימוש במודל LLM נפרד — או באותו מודל, אך בתפקיד נבדל ומבודד — כדי לדרג את איכות תשובה של המערכת הנבדקת מול קריטריונים מוגדרים מראש, במקום שאדם יעריך כל תשובה ידנית. למה צריך את זה? הערכה אנושית של כל תשובה מדויקת אך לא ניתנת לקנה מידה — לא ריאלי להריץ אדם על מאות מקרי בדיקה בכל שינוי prompt. LLM-as-judge פותר את בעיית קנה המידה: מודל יכול לדרג מאות תשובות תוך דקות ובעלות זניחה יחסית להערכה אנושית. המחיר הוא איכות שיפוט: השופט עצמו הוא LLM, ולכן נושא הטיות אופייניות (למשל נטייה להעדיף תשובות ארוכות יותר, או תשובות בסגנון קרוב לסגנון השופט עצמו) ורמת עקביות חלקית — אותה תשובה"}, {"file": "07-evaluation.html", "chapter": "7. Evaluation & Testing", "icon": "fa-flask", "id": "benchmarks", "title": "Benchmarks כלליים מול סטים ייעודיים", "text": "Benchmarks כלליים מול סטים ייעודיים מה זה? הבחנה בין מבחני יחס כלליים לדירוג מודלים (benchmark suites ציבוריים) לבין סט בדיקה ייעודי, שנבנה מתרחישי שימוש אמיתיים של המוצר הספציפי. למה צריך את זה? ציון גבוה ב-benchmark כללי אומר שהמודל חזק ביחס למודלים אחרים על משימות כלליות — הוא לא אומר דבר על האם המערכת שלך, עם ה-prompt, ה-RAG, וקהל המשתמשים הספציפיים שלך, בפועל עובדת טוב עבורם. איך זה עובד? benchmark כללי משמש בעיקר לבחירת מודל בסיס בשלב מוקדם; סט ייעודי, הנבנה מ golden dataset ומתרחישי משתמשים אמיתיים, הוא הכלי שמודד אם המערכת בפועל עומדת בדרישות המוצר. דוגמה מודל שמדורג גבוה ב-benchmark כ"}, {"file": "07-evaluation.html", "chapter": "7. Evaluation & Testing", "icon": "fa-flask", "id": "ab-testing-production", "title": "A/B Testing בייצור", "text": "A/B Testing בייצור מה זה? בדיקת שינוי — prompt חדש, מודל אחר, פייפליין RAG משופר — על אחוז קטן ומבוקר מהתנועה האמיתית בייצור, לפני rollout מלא לכלל המשתמשים. למה צריך את זה? evals לפני-ייצור (offline, מול golden dataset) בודקים איכות תשובה, אבל לא תמיד חוזים השפעה על מדדים עסקיים בפועל — שביעות רצון משתמשים, זמן שהייה, המרה. שינוי שמשפר ציון faithfulness ב-eval יכול בכל זאת להוריד מדד עסקי בגלל טון, אורך תשובה, או latency שלא נמדדו ב-eval הטכני. איך זה עובד? תנועת ייצור מפוצלת אקראית בין גרסה קיימת (control) לגרסה חדשה (treatment) באחוז קטן; מדדים עסקיים ומדדי איכות נאספים משתי הקבוצות במקביל "}, {"file": "07-evaluation.html", "chapter": "7. Evaluation & Testing", "icon": "fa-flask", "id": "golden-datasets", "title": "Golden Datasets", "text": "Golden Datasets מה זה? סט קבוע של שאלות או תרחישים, יחד עם תשובות או תכונות \"נכונות\" ידועות מראש, המשמש קו בסיס יציב להשוואת גרסאות שונות של המערכת לאורך זמן. למה צריך את זה? בלי סט קבוע, כל בדיקה משווה תפוחים לתפוזים — קלטים שונים בכל פעם, ולכן אי אפשר לדעת אם שינוי בציון נובע מהשינוי במערכת או משוני בקלטי הבדיקה עצמם. golden dataset קבוע מבודד את המשתנה היחיד שרוצים למדוד: השפעת השינוי במערכת. איך זה עובד? הסט נבנה פעם אחת (ומתעדכן מדי פעם בזהירות) מתוך מקרי שימוש אמיתיים או קריטיים במיוחד, כל אחד עם תשובת-ייחוס או קריטריון הצלחה מוגדר. כל גרסה חדשה של המערכת מורצת מול אותו הסט המדויק, כדי ש"}, {"file": "07-evaluation.html", "chapter": "7. Evaluation & Testing", "icon": "fa-flask", "id": "prompt-regression-testing", "title": "Prompt Regression Testing", "text": "Prompt Regression Testing מה זה? הרצה אוטומטית של golden dataset בכל שינוי ב-prompt או במודל, כדי לזהות ירידה באיכות לפני שהיא מגיעה למשתמשים — מקביל ל-unit tests בקוד רגיל, אך עם בדיקת דמיון או איכות במקום שוויון מדויק. למה צריך את זה? שינוי prompt שמתוקן ידנית (\"נראה שזה עובד יותר טוב על הדוגמה שבדקתי\") הוא ניחוש בלי הרצה שיטתית מול הסט הקבוע; regression testing הופך את הבדיקה לחוזרת ואוטומטית. איך זה עובד? סקריפט מריץ את ה-prompt החדש מול כל מקרה ב-golden dataset, משווה כל תשובה לתשובת הייחוס (באמצעות LLM-as-judge או מדד דמיון), ומפיק ציון כולל להשוואה מול הגרסה הקודמת. דוגמה צוות שעובד עם "}, {"file": "07-evaluation.html", "chapter": "7. Evaluation & Testing", "icon": "fa-flask", "id": "ci-cd-for-ai", "title": "CI/CD ל-AI", "text": "CI/CD ל-AI מה זה? שילוב סוויטת evals בצינור CI/CD: הרצה אוטומטית על כל pull request שמשנה prompt או לוגיקת AI, וחסימת מיזוג (merge) אם הציון יורד מתחת לסף שהוגדר מראש. למה צריך את זה? Prompt regression testing שמורץ ידנית \"כשנזכרים\" נשכח בדיוק כשהוא הכי נחוץ — תחת לחץ זמן לפני release. הטמעה בתוך ה-CI/CD הופכת את הבדיקה לשלב חובה שלא ניתן לעקוף, בדיוק כמו שבדיקות יחידה חוסמות merge של קוד שבור. איך זה עובד? שלב ייעודי בפייפליין ה-CI מריץ סקריפט evals על golden dataset מול הגרסה החדשה של ה-prompt או הלוגיקה, משווה לציון סף מוגדר, ומכשיל את השלב (ולכן חוסם merge) אם הציון נמוך מהסף — באותה צורה "}, {"file": "07-evaluation.html", "chapter": "7. Evaluation & Testing", "icon": "fa-flask", "id": "rag-eval-metrics", "title": "מדדי הערכת RAG: Faithfulness ו-Relevance", "text": "מדדי הערכת RAG: Faithfulness ו-Relevance מה זה? שני מדדים נפרדים ומשלימים להערכת פייפליין RAG : faithfulness — האם התשובה הסופית נאמנה אך ורק למסמכים שאוחזרו בפועל, בלי להוסיף פרטים שאינם מופיעים בהם. relevance — האם המסמכים שאוחזרו מלכתחילה רלוונטיים לשאלה שנשאלה. למה צריך את זה? פייפליין RAG יכול להיכשל בשני מקומות עצמאיים — שלב האחזור ושלב ה-generation — ומדד איכות יחיד ומאוחד מטשטש איפה בדיוק הכשל קרה. ההבחנה קריטית: אפשר לקבל תשובה נאמנה לחלוטין למסמכים שאוחזרו (faithfulness מושלם) כשהמסמכים עצמם אינם רלוונטיים לשאלה (relevance נמוך) — וזו עדיין כשל מלא של המערכת, גם אם המודל \"לא המציא\" ש"}, {"file": "07-evaluation.html", "chapter": "7. Evaluation & Testing", "icon": "fa-flask", "id": "real-world-example", "title": "Real World Example", "text": "Real World Example After Taste — golden dataset מינימלי כתרגול הערכה אמיתי אפליקציית מתכונים קטנה כמו After Taste ממחישה שהערכה שיטתית אינה דורשת תשתית כבדה. סוויטת evals מלאה, judge מתוחכם, ופייפליין CI/CD מרובה-שלבים — כל אלו רלוונטיים למערכות בקנה מידה גדול, אך לא הכרחיים כדי להתחיל. מה שכן הכרחי הוא golden dataset קבוע ומינימלי: עשר שאלות שחוזרות תמיד — \"כמה זמן אפייה לעוגת שוקולד\", \"האם המתכון מכיל אגוזים\", \"מה הכמות הנדרשת של קמח במתכון X\" — עם תשובות ידועות מראש. בכל שינוי בלוגיקת השליפה או בניסוח ה-prompt שמחזיר תשובות על מתכונים, מריצים את עשר השאלות מחדש ובודקים ידנית שהתשובות עדיין "}, {"file": "08-production.html", "chapter": "8. Production AI", "icon": "fa-shield-halved", "id": "security-prompt-injection", "title": "Security — Prompt Injection", "text": "Security — Prompt Injection מה זה? תוכן חיצוני — קלט משתמש, מסמך שאוחזר ב-RAG, תוצאת קריאת כלי — שמכיל הוראות המנסות לשנות את התנהגות המודל בניגוד לכוונת המערכת: Prompt injection ישיר — מגיע במסר המשתמש עצמו (\"התעלם מההוראות הקודמות ו...\"). Injection עקיף — מוטמע בתוכן שנטען ל-context בלי שהמשתמש כתב אותו — מסמך שאוחזר, דף אינטרנט, תוצאת API — ומנוצל כי המודל אינו מבחין באופן מהימן בין \"הוראות מהמערכת\" ל\"תוכן שיש לעבד\". למה צריך את זה? מודל LLM מעבד את כל הטקסט שבחלון ההקשר כרצף אחד — אין לו הפרדה מובנית ואמינה בין \"system prompt מהמפתח\" ל\"תוכן שאוחזר ממקור חיצוני\". agent עם גישה לכלים (שליחת "}, {"file": "08-production.html", "chapter": "8. Production AI", "icon": "fa-shield-halved", "id": "guardrails-output-validation", "title": "Guardrails — Output Validation למדיניות ובטיחות", "text": "Guardrails — Output Validation למדיניות ובטיחות מה זה? מסננים ברמת מדיניות ובטיחות שרצים לפני קריאת המודל (בדיקת קלט — rule-based או classifier ייעודי) ואחריה (בדיקת פלט לפני שהוא יוצא למשתמש או למערכת). המטרה: חסימת תוכן פוגעני, מניעת דליפת מידע רגיש, ומניעת סטייה מנושא המערכת — לא בדיקת תקינות טכנית. למה צריך את זה? הנחיה ב-system prompt שלא לענות על נושאים מסוימים אינה ערובה — מודל יכול לסטות ממנה בעקבות ניסוח משכנע, לחץ שיחה ממושך, או פשוט טעות. Guardrail חיצוני, שרץ כשכבה נפרדת מהמודל עצמו, הוא רשת ביטחון דטרמיניסטית או חצי-דטרמיניסטית שאינה תלויה בציות המודל להוראה — בדיוק כפי שאין לסמוך"}, {"file": "08-production.html", "chapter": "8. Production AI", "icon": "fa-shield-halved", "id": "logging", "title": "Logging", "text": "Logging מה זה? תיעוד שיטתי של כל קריאת LLM — פרומפט, תשובה, ומטא-דאטה (מודל, tokens, latency, עלות) — לצורך דיבוג, ביקורת, ושיפור מתמשך של המערכת. למה צריך את זה? בלי לוג מלא של הקריאה בפועל (לא רק \"משהו נכשל\"), אי אפשר לשחזר או לדבג התנהגות בעייתית שדווחה על ידי משתמש — ובלי היסטוריית קריאות אין בסיס לבניית golden dataset ממקרים אמיתיים. איך זה עובד? כל קריאה נרשמת עם prompt מלא, תשובה, וזמן/עלות; מידע אישי מזוהה או רגיש נמסך (masking) או מוחרג מהלוג בהתאם למדיניות פרטיות, כדי שהתיעוד עצמו לא ייצור סיכון חדש. דוגמה כשמשתמש מדווח על תשובה שגויה, לוג מלא של אותה קריאה — הפרומפט המדויק שנשלח, כו"}, {"file": "08-production.html", "chapter": "8. Production AI", "icon": "fa-shield-halved", "id": "monitoring-observability", "title": "Monitoring & Observability", "text": "Monitoring & Observability מה זה? מעקב בזמן אמת אחר בריאות המערכת: שיעורי שגיאה, latency, עלות, ואיכות תשובות. Monitoring — מדדים מצטברים לאורך זמן (dashboard של ממוצעים ומגמות). Observability — היכולת לחקור *למה* קרה משהו ספציפי — כולל trace מלא של קריאה בודדת, מקצה לקצה. למה צריך את זה? Dashboard שמראה \"שיעור שגיאה עלה ל-3%\" אומר *שיש* בעיה אך לא *מה* היא — לצורך זה נדרש trace שמראה בדיוק אילו שלבים (אחזור, קריאת כלי, קריאת מודל) התרחשו באותה קריאה כושלת ספציפית, ובאיזה שלב הכשל קרה. מערכת production שרק \"מודדת\" בלי יכולת לחקור מקרה בודד לעומק תקועה כשמדד חורג — יודעת שמשהו רע קורה בלי דרך ל"}, {"file": "08-production.html", "chapter": "8. Production AI", "icon": "fa-shield-halved", "id": "ai-gateway", "title": "AI Gateway", "text": "AI Gateway מה זה? שכבת ביניים מרכזית בין האפליקציה למודלים שונים, שמספקת ניתוב אחיד, ניהול מפתחות API, rate limiting, logging, ו fallback — במקום שכל שירות באפליקציה יטמיע אינטגרציה נפרדת ומלאה לכל ספק מודלים בנפרד. למה צריך את זה? ללא gateway מרכזי, כל שירות שקורא ל-LLM מטמיע בעצמו טיפול במפתחות, retry, לוגים, ומעבר בין ספקים — כפילות קוד שמכפילה גם באגים וגם מאמץ תחזוקה. gateway מרכז את הלוגיקה הזו במקום אחד: שינוי מדיניות rate limiting, הוספת ספק מודל חדש, או שדרוג מנגנון fallback נעשה פעם אחת ומשפיע על כל השירותים שמשתמשים ב-gateway, במקום שינוי נפרד בכל שירות. איך זה עובד? שירותי האפליקצי"}, {"file": "08-production.html", "chapter": "8. Production AI", "icon": "fa-shield-halved", "id": "fallback", "title": "Fallback", "text": "Fallback מה זה? מנגנון מעבר אוטומטי למודל או ספק חלופי כאשר הראשי נכשל, מחזיר שגיאה, או איטי מדי מעבר לסף מוגדר — כדי לשמור על זמינות המערכת מבלי לדרוש התערבות ידנית. למה צריך את זה? ספק מודל בודד, מוצלח ככל שיהיה, יכול לחוות תקלה זמנית, עומס יתר, או חריגת latency — תלות בספק יחיד הופכת את כל המוצר לפגיע לתקלה חיצונית שאינה בשליטת הצוות. fallback הופך תקלת ספק בודד מ\"המוצר לא זמין\" ל\"המוצר ממשיך לעבוד עם ירידה קלה, אם בכלל מורגשת\". איך זה עובד? ה- gateway מזהה כשל או latency חורג מהספק הראשי, ומעביר את הבקשה אוטומטית לספק/מודל חלופי מוגדר מראש, לרוב עם רישום מיוחד בלוג שמציין שהתבצע fallback. "}, {"file": "08-production.html", "chapter": "8. Production AI", "icon": "fa-shield-halved", "id": "caching", "title": "Caching רגיל מול Semantic Cache", "text": "Caching רגיל מול Semantic Cache מה זה? Cache רגיל — מחזיר תשובה שמורה כאשר הקלט זהה מילולית לקלט קודם. Semantic cache — מחזיר תשובה שמורה כאשר הקלט דומה סמנטית לקלט קודם, גם אם הניסוח שונה — מבוסס השוואת embeddings במקום השוואת מחרוזות. למה צריך את זה? קריאות LLM כרוכות בעלות ו-latency לא-זניחים; חיסכון קלט זהה חוזר על עצמו לעיתים רחוקות בפועל (\"מה השעה עכשיו בטוקיו\" נשאל פעם אחת בניסוח ספציפי), בעוד ששאלות דומות-משמעותית בניסוחים שונים (\"מה מזג האוויר מחר\", \"האם מחר יהיה גשם\") חוזרות בתדירות גבוהה בהרבה. semantic cache תופס את המקרה השני, שהוא הנפוץ יותר בפועל במוצרים מוכווני-שיחה. איך זה עוב"}, {"file": "08-production.html", "chapter": "8. Production AI", "icon": "fa-shield-halved", "id": "latency", "title": "Latency", "text": "Latency מה זה? הזמן מרגע שליחת בקשה ועד קבלת תשובה שלמה, המורכב מכמה גורמים: זמן ה-inference עצמו של המודל, גודל ה-context (פרומפט ארוך יותר איטי יותר לעבד), ואופן מסירת התוצאה — streaming (הצגת טוקנים בהדרגה) מול המתנה לתשובה מלאה לפני הצגה. למה צריך את זה? latency גבוה פוגע ישירות בחוויית משתמש ולעיתים בהמרה עסקית; אך latency נתפס (מה שהמשתמש חש) אינו זהה בהכרח ל-latency אמיתי (זמן העיבוד הכולל בפועל) — streaming יכול לגרום לתשובה שמתחילה להופיע מיד להיתפס כמהירה בהרבה מתשובה שמגיעה בבת אחת אחרי אותו זמן עיבוד כולל. איך זה עובד? צמצום latency אמיתי — בחירת מודל קטן/מהיר יותר למשימות שאינן דו"}, {"file": "08-production.html", "chapter": "8. Production AI", "icon": "fa-shield-halved", "id": "cost-optimization", "title": "Cost Optimization", "text": "Cost Optimization מה זה? אסטרטגיות מוגדרות לצמצום עלות הפעלת מערכת LLM בייצור: בחירת מודל לפי מורכבות המשימה בפועל, caching , קיצור prompts מיותרים, והגבלת max tokens — כל זאת בלי לפגוע באיכות התשובה מעבר לסף מקובל. למה צריך את זה? עלות LLM נגזרת ישירות מנפח tokens (קלט ופלט) ומהמודל הנבחר; מערכת שמריצה כל בקשה, ללא הבחנה, דרך המודל החזק ביותר עם context מלא ומיותר, משלמת עלות מיותרת פעם אחר פעם — עלות שמצטברת משמעותית בקנה מידה של ייצור, גם אם היא זניחה בבדיקה בודדת בפיתוח. איך זה עובד? שילוב טכניקות: model routing שבוחר מודל זול/מהיר למשימות פשוטות ומודל חזק רק כשנדרש. Caching שמונע קריאה חו"}, {"file": "08-production.html", "chapter": "8. Production AI", "icon": "fa-shield-halved", "id": "model-routing", "title": "Model Routing", "text": "Model Routing מה זה? ניתוב דינמי בין מודלים שונים בהתאם למורכבות, עלות, ו-latency נדרשים למשימה הספציפית — מודל קל ומהיר למשימות פשוטות (סיווג, חילוץ שדה בודד), מודל חזק ויקר יותר למשימות מורכבות (נימוק רב-שלבי, כתיבה יצירתית מדויקת). למה צריך את זה? שימוש קבוע במודל החזק ביותר לכל בקשה, ללא הבחנה, מבזבז עלות ו-latency על הרוב הגדול של הבקשות שאינן דורשות את יכולותיו המלאות; שימוש קבוע במודל חלש כדי לחסוך פוגע באיכות בדיוק במקרים המורכבים שבהם ההבדל בין מודלים משמעותי ביותר. ניתוב דינמי פותר את שני הכשלים בו-זמנית. איך זה עובד? שכבת ניתוב — לרוב חלק מ AI gateway — מסווגת כל בקשה נכנסת (לפי כלל"}, {"file": "08-production.html", "chapter": "8. Production AI", "icon": "fa-shield-halved", "id": "rate-limiting", "title": "Rate Limiting", "text": "Rate Limiting מה זה? הגבלת קצב הבקשות המותרות בפרק זמן נתון — ברמת משתמש בודד וברמת המערכת כולה — כדי למנוע עומס יתר, לשלוט בעלות, ולעמוד במגבלות הקצב שמטיל ספק המודל עצמו. למה צריך את זה? בלי הגבלה, משתמש בודד (בזדון או בטעות, למשל לולאה שבורה בקוד לקוח) יכול לצרוך חלק בלתי-פרופורציונלי ממכסת הספק או מהתקציב, ולפגוע בזמינות עבור כלל המשתמשים. איך זה עובד? נאכף לרוב ברמת ה- AI gateway : מכסת בקשות או tokens למשתמש בחלון זמן נתון, וכן מכסה כוללת ברמת המערכת שמתואמת מול מגבלות הספק עצמו, עם תגובת שגיאה ברורה כשהמכסה נחצית. דוגמה gateway שמנתב בקשות ל-Claude/GPT/Gemini אוכף מכסת בקשות-לדקה לכל מש"}, {"file": "08-production.html", "chapter": "8. Production AI", "icon": "fa-shield-halved", "id": "real-world-example", "title": "Real World Example", "text": "Real World Example AI Gateway רב-מודלי עם Fallback וניתוב מבוסס עלות צוות שבונה מוצר מבוסס LLM עם תלות בזמינות גבוהה מטמיע AI gateway יחיד שכל שירותי האפליקציה קוראים לו דרך ממשק אחיד, בלי לדעת איזה ספק בפועל מטפל בבקשה. ה-gateway מחזיק את מפתחות ה-API של Claude, GPT ו-Gemini, ומיישם model routing : בקשות סיווג ותיוג פשוטות מנותבות למודל קל ומהיר, בעוד משימות שדורשות נימוק מורכב מנותבות למודל חזק יותר — לפי הטבלה המפורטת בפרק 9. כשהספק הראשי לבקשה נתונה מחזיר שגיאה או חורג מסף latency מוגדר, מנגנון fallback מעביר אותה אוטומטית לספק חלופי, כדי שכשל זמני אצל ספק בודד לא יפיל את המוצר כולו. כל בק"}, {"file": "09-architecture-cheatsheet.html", "chapter": "9. Architecture & Cheat Sheet", "icon": "fa-map", "id": "full-architecture", "title": "ארכיטקטורה מלאה", "text": "ארכיטקטורה מלאה מה זה? מסלול חיים מלא של בקשה במערכת LLM production, מקצה לקצה — מרגע שהמשתמש שולח קלט ועד שהתשובה חוזרת אליו. כל שלב בתרשים מייצג שכבה אחרת בפרקים 1–8 של הספר. User שולח בקשה או שאלה בממשק המוצר. Frontend קולט את הקלט ומעביר לבקאנד, מציג בהמשך את התשובה (לרוב עם streaming). Backend מתאם את כל שלבי העיבוד, אכיפת מדיניות, ו-rate limiting. Memory טוען הקשר שיחה קודם רלוונטי למשתמש. Vision מעבד קלט חזותי אם קיים (תמונה, מסמך סרוק). RAG / Tools מאחזר מסמכים רלוונטיים ו/או מפעיל כלים חיצוניים לפי הצורך. Prompt Builder מרכיב את הפרומפט הסופי מכל המקורות — system, זיכרון, RAG, קלט. AI"}, {"file": "09-architecture-cheatsheet.html", "chapter": "9. Architecture & Cheat Sheet", "icon": "fa-map", "id": "pre-request-checklist", "title": "Cheat Sheet — לפני כל בקשה", "text": "Cheat Sheet — לפני כל בקשה למה צריך את זה? שישה מרכיבים שכדאי לוודא במפורש לפני שליחת כל קריאת LLM — רשימת בדיקה מהירה, לא הסבר מחודש. System Prompt — מוגדר בבירור, כולל תפקיד, מגבלות, וטון, ומעודכן לגרסה הנוכחית של המוצר. User Prompt — הקלט מנוסח או מעובד בצורה שמפרידה אותו בבירור מהוראות המערכת. Memory — רק הקשר שיחה רלוונטי ועדכני נטען, לא היסטוריה גורפת שמנפחת את ה-context לחינם. RAG — אחזור המסמכים תואם את השאלה בפועל, ותוצאות שאינן רלוונטיות מסוננות לפני הכנסה ל-prompt. Max Tokens — מוגבל לפי צורך אמיתי של סוג הבקשה, לא ברירת מחדל גבוהה גורפת. Temperature — מותאם למשימה: נמוך למשימות עקב"}, {"file": "09-architecture-cheatsheet.html", "chapter": "9. Architecture & Cheat Sheet", "icon": "fa-map", "id": "decision-cheatsheet", "title": "Cheat Sheet — החלטות ארכיטקטורה נפוצות", "text": "Cheat Sheet — החלטות ארכיטקטורה נפוצות למה צריך את זה? שמונה שאלות שחוזרות בכל תכנון מערכת LLM — מיפוי מהיר בין מצב לבחירה מומלצה, עם קישור לפרק המרחיב. זו טבלת עיון, לא הסבר מחודש של המושגים. מצב → החלטה המצב הבחירה המומלצת הרחבה המודל צריך גישה למידע עדכני, פרטי, או שלא היה חלק מהאימון RAG פרק 3 צריך לשנות סגנון, פורמט, או התנהגות קבועה של המודל באופן עקבי בכל קריאה Fine-Tuning פרק 3 המודל צריך לבצע פעולה בעולם האמיתי — קריאה ל-API, הרצת קוד, שליפת נתון חי Tool Calling פרק 5 המשימה דורשת כמה צעדים תלויי-תוצאה, שהרצף המדויק ביניהם לא ידוע מראש Agent (לולאת Agent) פרק 5 יש טווח משימות ברמות מו"}, {"file": "09-architecture-cheatsheet.html", "chapter": "9. Architecture & Cheat Sheet", "icon": "fa-map", "id": "model-selection", "title": "בחירת מודל — מדריך החלטה", "text": "בחירת מודל — מדריך החלטה איך זה עובד? בחירת מודל נכונה מבוססת על קריטריונים ארכיטקטוניים, לא על שם מודל ספציפי שמתיישן במהירות: Context window נדרש — כמה טקסט (מסמכים, היסטוריית שיחה, תוצאות כלים) חייב להיכנס לפרומפט בבת אחת. רמת עלות — עלות לטוקן מוכפלת בנפח הקריאות בקנה מידה של ייצור, לא רק בעלות קריאה בודדת. איכות tool-use / function-calling — עד כמה המודל אמין בבחירת הכלי הנכון ובמילוי פרמטרים תקינים, קריטי במיוחד למערכות agentic. דרישות latency — האם המשימה דורשת תגובה כמעט-מיידית (ממשק שיחתי חי) או שיש סובלנות לזמן עיבוד ארוך יותר (עיבוד אצווה ברקע). self-hosting / open-weight — נדרש כאש"}, {"file": "09-architecture-cheatsheet.html", "chapter": "9. Architecture & Cheat Sheet", "icon": "fa-map", "id": "model-quick-reference", "title": "Model Quick Reference", "text": "Model Quick Reference השוואת משפחות מודלים לפי מחלקת יכולת משפחה חוזקות טיפוסיות Context Window טיפוסי מתי לבחור מודלים מובילים (flagship) נימוק מורכב, tool-use אמין, ביצועים גבוהים במגוון רחב של משימות גדול משימות agentic רבות-שלבים, החלטות בעלות השפעה גבוהה, כתיבה/ניתוח מורכבים מודלים קלים/מהירים (lightweight) latency נמוך, עלות לטוקן זולה משמעותית בינוני עד גדול סיווג, חילוץ שדה בודד, משימות בנפח גבוה שאינן דורשות נימוק עמוק מודלים open-weight/self-hosted שליטה מלאה בסביבת ההרצה, ללא תלות בספק חיצוני משתנה לפי דגם דרישת residency נתונים, עלות בקנה מידה גדול, סביבות מבודדות/ללא חיבור לרשת חי"}, {"file": "09-architecture-cheatsheet.html", "chapter": "9. Architecture & Cheat Sheet", "icon": "fa-map", "id": "glossary", "title": "מילון מונחים", "text": "מילון מונחים Agent מערכת מבוססת LLM שמתכננת ומבצעת רצף פעולות באופן איטרטיבי, כולל קריאת כלים, לצורך השגת מטרה. AI (Artificial Intelligence) תחום העוסק בבניית מערכות שמבצעות משימות שבדרך כלל דורשות אינטליגנציה אנושית. AI Gateway שכבת ביניים מרכזית בין האפליקציה למודלים שונים, המספקת ניתוב, ניהול מפתחות, rate limiting, ו-fallback במקום אחד. Chunking חלוקת מסמכים ארוכים ליחידות (chunks) קטנות יותר לפני יצירת embeddings, לצורך אחזור יעיל ומדויק ב-RAG. Context (Context Window) כמות הטוקנים המקסימלית שמודל יכול לעבד בבת אחת בקריאה בודדת, כולל קלט ופלט יחד. Embedding ייצוג וקטורי מספרי של טקסט (או ת"}];
